async (params, browser) => {
  // Open job posting
  await browser.open(`${params.job_url}`)

  // Wait for job details to load
  await browser.waitForSelector('.jobsearch-JobInfoHeader-title, h1.jobsearch-JobInfoHeader-title, [data-testid="jobsearch-JobInfoHeader-title"], .jobs-unified-top-card__job-title', 15000)

  // Let page settle
  await browser.wait(2000)

  // Scroll to load full description
  await browser.scroll({ direction: 'down', amount: 600 })

  await browser.wait(1500)

  // Extract job details
  const job_details = await browser.evaluate(`const titleEl = document.querySelector('.jobsearch-JobInfoHeader-title, h1.jobsearch-JobInfoHeader-title, [data-testid="jobsearch-JobInfoHeader-title"], h2.icl-u-xs-mb--xs'); const companyEl = document.querySelector('[data-testid="inlineHeader-companyName"] a, .jobsearch-InlineCompanyRating a, div.icl-u-lg-mr--sm a, [data-company-name="true"] a'); const locationEl = document.querySelector('[data-testid="inlineHeader-companyLocation"], .jobsearch-InlineCompanyRating div:last-child, div.icl-u-xs-mt--xs .icl-u-textColor--secondary'); const salaryEl = document.querySelector('#salaryInfoAndJobType span, .jobsearch-JobMetadataHeader-item, [data-testid="attribute_snippet_testid"], .salary-snippet-container'); const jobTypeEl = document.querySelector('#salaryInfoAndJobType .css-k5flys, .jobsearch-JobMetadataHeader-item:last-child'); const descEl = document.querySelector('#jobDescriptionText, .jobsearch-jobDescriptionText, [data-testid="jobDescriptionText"]'); const qualsList = []; if (descEl) { const listItems = descEl.querySelectorAll('ul li'); listItems.forEach(function(li, i) { if (i < 15) qualsList.push(li.textContent.trim()); }); } const benefitsEls = document.querySelectorAll('.jobsearch-benefits li, [data-testid="benefits-item"], .css-1r0wrwl li'); const benefits = []; benefitsEls.forEach(function(el) { benefits.push(el.textContent.trim()); }); const ratingEl = document.querySelector('.jobsearch-InlineCompanyRating .icl-Ratings-starsCountWrapper, [data-testid="inlineHeader-companyRating"], .css-1unnuiz'); return { title: titleEl ? titleEl.textContent.trim() : 'Unknown', company: companyEl ? companyEl.textContent.trim() : '', location: locationEl ? locationEl.textContent.trim() : '', salary: salaryEl ? salaryEl.textContent.trim() : 'Not listed', job_type: jobTypeEl ? jobTypeEl.textContent.trim() : '', company_rating: ratingEl ? ratingEl.textContent.trim() : '', description: descEl ? descEl.textContent.trim().slice(0, 3000) : '', requirements: qualsList, benefits: benefits, url: window.location.href }`)

  return job_details
}
